package ir.tahamohamadi.skill; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="skill") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class Skill extends AuditedSoftDeletableEntity { @Column(name="skill_key",nullable=false) private String skillKey; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="skill_category_id",nullable=false) private SkillCategory category; @Column(name="sort_order",nullable=false) private int sortOrder; @Column(name="is_active",nullable=false) private boolean active; private Skill(UUID id,String key,SkillCategory category,int order,Instant at){initialize(id,at);skillKey=requireNonBlank(key,"skillKey");this.category=Objects.requireNonNull(category,"category");if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");sortOrder=order;active=true;} public static Skill create(UUID id,String key,SkillCategory category,int order,Instant at){return new Skill(id,key,category,order,at);} public void update(String key,SkillCategory category,int order){skillKey=requireNonBlank(key,"skillKey");this.category=Objects.requireNonNull(category,"category");if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");sortOrder=order;updatedAt=Instant.now();} public void activate(){active=true;updatedAt=Instant.now();} public void deactivate(){active=false;updatedAt=Instant.now();} }
